import{_ as r,o,c as a,a2 as n}from"./chunks/framework.DGp-bpT-.js";const c=JSON.parse('{"title":"Управление командой","description":"","frontmatter":{},"headers":[],"relativePath":"guide/team-management.md","filePath":"guide/team-management.md","lastUpdated":1779958375000}'),s={name:"guide/team-management.md"};function e(l,t,i,d,g,p){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="управление-командои" tabindex="-1">Управление командой <a class="header-anchor" href="#управление-командои" aria-label="Permalink to &quot;Управление командой&quot;">​</a></h1><p>Раздел <strong>«Команда»</strong> позволяет владельцу и администраторам организации управлять составом участников, выдавать приглашения и разграничивать доступ к функциям платформы.</p><h2 id="роли-пользователеи" tabindex="-1">Роли пользователей <a class="header-anchor" href="#роли-пользователеи" aria-label="Permalink to &quot;Роли пользователей&quot;">​</a></h2><p>В каждой организации SREBot используется четырёхуровневая ролевая модель. Набор доступных действий зависит от назначенной роли.</p><table tabindex="0"><thead><tr><th>Роль</th><th>Инциденты</th><th>Биллинг</th><th>Настройки ботов</th><th>Управление командой</th></tr></thead><tbody><tr><td><strong>Владелец</strong> (Owner)</td><td>✅ Просмотр</td><td>✅ Полный доступ</td><td>✅ Полный доступ</td><td>✅ Полный доступ</td></tr><tr><td><strong>Администратор</strong> (Admin)</td><td>✅ Просмотр</td><td>✅ Полный доступ</td><td>✅ Полный доступ</td><td>✅ Приглашения и управление участниками</td></tr><tr><td><strong>Участник</strong> (Member)</td><td>✅ Просмотр</td><td>❌ Нет доступа</td><td>❌ Нет доступа</td><td>❌ Нет доступа</td></tr><tr><td><strong>Наблюдатель</strong> (Viewer)</td><td>✅ Просмотр</td><td>❌ Нет доступа</td><td>❌ Нет доступа</td><td>❌ Нет доступа</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Одна организация — один владелец</p><p>У каждой организации всегда есть ровно один <strong>Владелец</strong>. Создатель организации автоматически получает эту роль. Владельца нельзя удалить из организации и понизить в роли — только сменить посредством <strong>передачи владения</strong>.</p></div><h3 id="описание-ролеи" tabindex="-1">Описание ролей <a class="header-anchor" href="#описание-ролеи" aria-label="Permalink to &quot;Описание ролей&quot;">​</a></h3><p><strong>Владелец (Owner)</strong></p><p>Высшая роль в организации. Только Владелец может:</p><ul><li>Передать владение организацией другому участнику.</li><li>Повышать участников до уровня Администратора.</li><li>Удалять Администраторов из организации.</li></ul><p><strong>Администратор (Admin)</strong></p><p>Может управлять командой: приглашать новых участников, изменять их роли (в пределах Member и Viewer), удалять рядовых участников. Не может изменять роль или удалять Владельца и других Администраторов.</p><p><strong>Участник (Member)</strong></p><p>Полноценный участник команды с доступом к аналитике инцидентов. Не имеет доступа к биллингу, настройкам ботов и управлению командой.</p><p><strong>Наблюдатель (Viewer)</strong></p><p>Минимальный уровень доступа. Может только просматривать список и детали инцидентов.</p><hr><h2 id="приглашение-участников" tabindex="-1">Приглашение участников <a class="header-anchor" href="#приглашение-участников" aria-label="Permalink to &quot;Приглашение участников&quot;">​</a></h2><p>Пригласить нового пользователя может <strong>Владелец</strong> или <strong>Администратор</strong>.</p><ol><li>Перейдите в раздел <strong>Команда</strong> в боковом меню.</li><li>В форме <strong>«Пригласить нового участника»</strong> введите email-адрес и выберите роль.</li><li>Нажмите <strong>«Отправить приглашение»</strong>.</li></ol><p>На указанный email будет отправлена ссылка, действительная <strong>48 часов</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Выбор роли при приглашении</p><p>Вы можете пригласить пользователя как <strong>Наблюдателя</strong>, <strong>Участника</strong> или <strong>Администратора</strong>. Роль <strong>Владелец</strong> при приглашении недоступна — её можно передать только уже действующему участнику организации.</p></div><h3 id="принятие-приглашения" tabindex="-1">Принятие приглашения <a class="header-anchor" href="#принятие-приглашения" aria-label="Permalink to &quot;Принятие приглашения&quot;">​</a></h3><p>Пользователь переходит по ссылке из письма. Дальнейший сценарий зависит от того, зарегистрирован ли он в SREBot:</p><p><strong>Новый пользователь</strong></p><p>Отображается форма создания аккаунта. Необходимо задать пароль (минимум 8 символов). После нажатия кнопки пользователь автоматически авторизуется и попадает в панель управления.</p><p><strong>Существующий пользователь</strong></p><p>Отображается форма подтверждения личности. Необходимо ввести пароль от существующего аккаунта. Это требование защищает от несанкционированного доступа в случае перехвата ссылки.</p><div class="warning custom-block"><p class="custom-block-title">Безопасность ссылки-приглашения</p><p>Ссылка истекает через 48 часов. Никогда не публикуйте её в общедоступных местах — любой, кто получит ссылку, сможет принять приглашение. Если ссылка была скомпрометирована, отзовите приглашение в разделе <strong>«Ожидающие приглашения»</strong>.</p></div><hr><h2 id="управление-участниками" tabindex="-1">Управление участниками <a class="header-anchor" href="#управление-участниками" aria-label="Permalink to &quot;Управление участниками&quot;">​</a></h2><p>Список всех текущих участников организации отображается в таблице <strong>«Активные участники»</strong>.</p><h3 id="изменение-роли" tabindex="-1">Изменение роли <a class="header-anchor" href="#изменение-роли" aria-label="Permalink to &quot;Изменение роли&quot;">​</a></h3><p>Владелец и Администратор могут изменять роли участников через выпадающее меню в столбце <strong>«Действия»</strong>.</p><p>Ограничения:</p><ul><li><strong>Администратор</strong> не может изменить роль <strong>Владельца</strong> или другого <strong>Администратора</strong>.</li><li><strong>Администратор</strong> не может повышать участников до <strong>Администратора</strong> — это право есть только у Владельца.</li><li>Никто не может изменить свою собственную роль.</li></ul><h3 id="удаление-участника" tabindex="-1">Удаление участника <a class="header-anchor" href="#удаление-участника" aria-label="Permalink to &quot;Удаление участника&quot;">​</a></h3><p>Нажмите на иконку корзины в строке нужного участника. Вам будет предложено подтвердить действие.</p><p>Ограничения:</p><ul><li><strong>Владельца</strong> нельзя удалить из организации.</li><li><strong>Администратор</strong> не может удалить другого <strong>Администратора</strong>.</li><li>Нельзя удалить самого себя из организации.</li></ul><hr><h2 id="передача-владения-организациеи" tabindex="-1">Передача владения организацией <a class="header-anchor" href="#передача-владения-организациеи" aria-label="Permalink to &quot;Передача владения организацией&quot;">​</a></h2><p>Если вы являетесь <strong>Владельцем</strong> и хотите передать организацию другому участнику:</p><ol><li>Перейдите в раздел <strong>Команда</strong>.</li><li>В строке нужного участника выберите роль <strong>«Owner (Transfer)»</strong> из выпадающего меню.</li><li>Подтвердите действие в диалоговом окне.</li></ol><div class="danger custom-block"><p class="custom-block-title">Внимание: необратимое действие</p><p>После передачи владения вы автоматически понижаетесь до роли <strong>Администратора</strong>. Новый Владелец получает полный контроль над организацией, включая право на дальнейшую передачу владения.</p></div><hr><h2 id="управление-приглашениями" tabindex="-1">Управление приглашениями <a class="header-anchor" href="#управление-приглашениями" aria-label="Permalink to &quot;Управление приглашениями&quot;">​</a></h2><p>В блоке <strong>«Ожидающие приглашения»</strong> (виден только Владельцу и Администраторам) отображаются все отправленные, но ещё не принятые приглашения.</p><ul><li>Для каждого приглашения отображаются: email, назначенная роль и дата истечения.</li><li>Нажмите кнопку <strong>«Отозвать»</strong> чтобы аннулировать приглашение до его принятия.</li><li>По истечении 48 часов приглашение автоматически становится недействительным.</li></ul>',49)])])}const m=r(s,[["render",e]]);export{c as __pageData,m as default};
